var cluster = require("cluster");
var http = require("http");
var os = require("os");

if (cluster.isPrimary) {
  // Master process
  var cpuCount = os.cpus().length;
  console.log("Master PID:", process.pid);
  console.log("Forking " + cpuCount + " workers");

  for (var i = 0; i < cpuCount; i++) {
    cluster.fork();
  }

  cluster.on("exit", function(worker, code, signal) {
    console.log("Worker " + worker.process.pid + " exited");
    console.log("Forking replacement...");
    cluster.fork();
  });
} else {
  // Worker process
  http.createServer(function(req, res) {
    res.writeHead(200, { "Content-Type": "text/plain" });
    res.end("Worker " + cluster.worker.id + " handled request\n");
  }).listen(3000);

  console.log("Worker " + cluster.worker.id + " started, PID:", process.pid);
}

var cluster = require("cluster");
var http = require("http");
var os = require("os");

if (cluster.isPrimary) {
  var workers = [];
  for (var i = 0; i < os.cpus().length; i++) {
    workers.push(cluster.fork());
  }

  // Graceful master shutdown
  process.on("SIGTERM", function() {
    console.log("Master received SIGTERM, shutting down workers");
    workers.forEach(function(worker) {
      worker.disconnect();
      worker.kill("SIGTERM");
    });
  });
} else {
  var server = http.createServer(function(req, res) {
    // Simulate long request
    setTimeout(function() {
      res.end("Worker " + cluster.worker.id + " done\n");
    }, 1000);
  });

  server.listen(3000);

  // Graceful worker shutdown
  process.on("SIGTERM", function() {
    console.log("Worker " + cluster.worker.id + " shutting down");
    server.close(function() {
      console.log("Worker " + cluster.worker.id + " closed");
      process.exit(0);
    });
  });
}

var cluster = require("cluster");
var http = require("http");
var os = require("os");

if (cluster.isPrimary) {
  var restartCounts = {};

  function createWorker() {
    var worker = cluster.fork();
    var id = worker.id;
    if (!restartCounts[id]) restartCounts[id] = 0;

    worker.on("exit", function(code, signal) {
      restartCounts[id]++;
      var count = restartCounts[id];

      if (count > 10) {
        console.error("Worker " + id + " crashed too many times");
        return;
      }

      // Exponential backoff: 1s, 2s, 4s, 8s, ...
      var delay = Math.min(1000 * Math.pow(2, count - 1), 30000);
      console.log("Worker " + id + " crashed (attempt " + count + "),",
        "restarting in " + delay + "ms");

      setTimeout(createWorker, delay);
    });

    // Health check via IPC
    worker.on("message", function(msg) {
      if (msg.type === "health") {
        restartCounts[id] = 0; // Reset on successful health check
      }
    });

    return worker;
  }

  for (var i = 0; i < os.cpus().length; i++) {
    createWorker();
  }
} else {
  var server = http.createServer(function(req, res) {
    res.end("OK from worker " + cluster.worker.id);
  }).listen(3000);

  // Send periodic health check to master
  setInterval(function() {
    process.send({ type: "health", pid: process.pid });
  }, 5000);
}

var cluster = require("cluster");
var http = require("http");

if (cluster.isPrimary) {
  var worker = cluster.fork();

  // Master receives messages from workers
  worker.on("message", function(msg) {
    console.log("Master received:", JSON.stringify(msg));
    if (msg.type === "request_count") {
      worker.send({ type: "response", data: "Count: " + msg.count });
    }
  });

  // Master sends messages to workers
  worker.send({ type: "greeting", text: "Hello from master!" });
} else {
  var requestCount = 0;

  // Worker receives messages from master
  process.on("message", function(msg) {
    console.log("Worker received:", JSON.stringify(msg));
  });

  http.createServer(function(req, res) {
    requestCount++;
    res.end("OK\n");
    // Notify master about request count periodically
    if (requestCount % 5 === 0) {
      process.send({
        type: "request_count",
        count: requestCount,
        pid: process.pid
      });
    }
  }).listen(3000);
}

var cluster = require("cluster");
var http = require("http");
var crypto = require("crypto");

// Hash-based sticky session using client IP
function getWorkerId(remoteAddress, numWorkers) {
  var hash = crypto.createHash("md5").update(remoteAddress).digest("hex");
  return parseInt(hash.slice(0, 8), 16) % numWorkers;
}

if (cluster.isPrimary) {
  var numWorkers = 4;
  for (var i = 0; i < numWorkers; i++) {
    cluster.fork();
  }

  // Round-robin is default, but we handle sticky in the load balancer
  cluster.on("exit", function(worker) {
    cluster.fork();
  });
} else {
  var sessionData = {};
  http.createServer(function(req, res) {
    // Simulate session-based state
    var sessionId = req.headers["cookie"] || "anon";
    if (!sessionData[sessionId]) {
      sessionData[sessionId] = { visits: 0 };
    }
    sessionData[sessionId].visits++;
    res.writeHead(200, { "Content-Type": "text/plain" });
    res.end("Worker " + cluster.worker.id
      + " - Visit " + sessionData[sessionId].visits');
  }).listen(3000);
}
